// n8n Function node
// Keeps image array from input, inserts embedding_text inline with images

const pages = items[0].json.pages;
let output = [];

for (const page of pages) {
  let text = `Page ${page.index}\n\n`;
  let markdown = page.markdown;

  // Replace each image markdown with annotation text if available
  markdown = markdown.replace(/!\[(.*?)\]\((.*?)\)/g, (match, alt, src) => {
    const img = page.images.find(i => i.id === src || i.fileName === src);
    if (img && img.image_annotation) {
      const ann = JSON.parse(img.image_annotation);
      return (
        '{' +
        `Image: [${img.id}]\n` +
        `Type: ${ann.image_type}\n` +
        `Short: ${ann.short_description}\n` +
        `Summary: ${ann.summary}\n` +
        '}'
      );
    }
    return ""; // if no annotation, strip it
  });

  text += markdown.trim();

  output.push({
    json: {
      page_index: page.index,
      embedding_text: text,
      images: page.images   // ✅ keep original images array
    }
  });
}

return output;

// Code10 (idempotent): If input is already chunked, pass through. Otherwise perform chunking.
// Config:
const DEFAULT_CHUNK_SIZE = 1800;   // desired chunk size
const DEFAULT_OVERLAP = 0.3;       // 30% overlap

// Helpers
function isAlreadyChunkedInput(items) {
  // Heuristic: if the first item content is a JSON string with pageContent OR metadata includes chunk_index
  if (!items || items.length === 0) return false;
  try {
    const first = items[0].json;
    if (!first) return false;
    // if content looks like already chunked object stringified
    if (typeof first.content === 'string') {
      const parsed = JSON.parse(first.content);
      if (parsed && (parsed.pageContent || parsed.metadata?.chunk_index !== undefined)) {
        return true;
      }
    }
    // or if the node already has chunk metadata at top level
    if (first.metadata && first.metadata.chunk_index !== undefined) return true;
    // or if the input is many short items likely produced by splitter -> treat as already split
    if (items.length > 1 && items.every(it => (it.json.content || '').length <= DEFAULT_CHUNK_SIZE)) {
      return true;
    }
  } catch (e) {
    // ignore parse errors -> assume not chunked
  }
  return false;
}

function getObjLength(obj) {
  return (obj.content || '').length;
}
function getObjLengthofTextOnly(obj) {
  if (obj.type === 'image_ocr') return 0;
  return (obj.content || '').length;
}

// split with overlap for a single large text string
function splitTextWithOverlap(text, chunkSize, overlap) {
  const step = Math.max(1, Math.floor(chunkSize * (1 - overlap)));
  const parts = [];
  for (let start = 0; start < text.length; start += step) {
    parts.push(text.slice(start, start + chunkSize));
  }
  return parts;
}

// Main chunking function which accepts an array of objects (items) and returns array of { content, metadata }
function chunkPageItems(arr, source, source_id, pageNum, chunkSize = DEFAULT_CHUNK_SIZE, overlap = DEFAULT_OVERLAP) {
  // Flatten content strings
  const pageText = arr.map(it => it.content || '').join(' ');

  // Use splitTextWithOverlap to produce chunks
  const parts = splitTextWithOverlap(pageText, chunkSize, overlap);
  const response = [];
  let charPos = 0;
  for (let i = 0; i < parts.length; i++) {
    const part = parts[i];
    const from = charPos;
    const to = charPos + (part || '').length;
    const metadata = {
      source,
      source_metadata_id: source_id,
      loc: { page: pageNum, Characters: { from, to } },
      chunk_index: i
    };
    response.push({
      content: JSON.stringify({
        pageContent: [{ type: 'text', content: part }],
        metadata
      })
    });
    charPos = to;
  }
  return response;
}

// --- Entrypoint ---
const incoming = $input.all(); // array of items from previous node
// If already chunked, pass through (normalize if needed)
if (isAlreadyChunkedInput(incoming)) {
  // Optionally normalize metadata for each item if not present
  const pass = incoming.map((it, idx) => {
    const json = it.json || {};
    // ensure content is stringified chunk object (if it's already an object, keep it)
    if (typeof json.content === 'object' && json.content !== null) {
      return { json: { content: JSON.stringify(json.content), metadata: json.metadata || {} } };
    }
    // if content is a raw string that's small, assume it's already a chunk
    return { json: { content: json.content, metadata: json.metadata || { chunk_index: idx } } };
  });
  return pass;
}

// Otherwise: Not chunked — perform chunking based on raw document pages
// We expect input format: first item has fields: 'Document data' (array of pages), 'Document name', and insert metadata node contains id
const first = incoming[0] ? incoming[0].json : {};
const raw = first['Document data'] || []; // array of page strings
const source = first['Document name'] || (first.metadata && first.metadata.source) || '';
// fallback for source_id from Set File ID node
let source_id = '';
try {
  source_id = $('Insert Document Metadata2').first().json.id || $('Set File ID1').first().json.file_id || '';
} catch (e) {
  // safe fallback
  source_id = first.metadata?.source_metadata_id || '';
}

// Build chunks page by page
let allChunks = [];
raw.forEach((pageText, pageIndex) => {
  // pageText may be a string or array of small blocks; normalize to array of objects
  let arr = [];
  if (Array.isArray(pageText)) {
    arr = pageText;
  } else {
    arr = [{ type: 'text', content: pageText }];
  }
  const pageChunks = chunkPageItems(arr, source, source_id, pageIndex + 1, DEFAULT_CHUNK_SIZE, DEFAULT_OVERLAP);
  allChunks.push(...pageChunks);
});

// Return in n8n format
return allChunks.map(c => ({ json: c }));

// n8n Code Node - SharePoint URL with Version Parameter
// Use this in a "Code" node in n8n

const items = $input.all();

const outputItems = items.map(item => {
  const data = item.json;

  // Use existing LinkingUrl if available
  if (data.LinkingUrl) {
    return {
      json: {
        ...data,
        fileUrl: data.LinkingUrl
      }
    };
  }

  // Construct versioned URL
  let fileUrl = '';

  if (data.ServerRelativeUrl && data.ContentTag) {
    // Base URL with server relative path
    fileUrl = 'https://nosta.sharepoint.com' + data.ServerRelativeUrl;

    // Extract GUID from ContentTag and create version parameter
    const guidMatch = data.ContentTag.match(/\{([^}]+)\}/);
    if (guidMatch) {
      const versionId = guidMatch[1].toLowerCase().replace(/-/g, '');
      fileUrl += `?d=w${versionId}`;
    }
  }

  return {
    json: {
      ...data,
      fileUrl: fileUrl
    }
  };
});

return outputItems;

// n8n Code Node - SharePoint URL with Version Parameter
// Use this in a "Code" node in n8n

const items = $input.all();

const outputItems = items.map(item => {
  const data = item.json;

  // Use existing LinkingUrl if available
  if (data.LinkingUrl) {
    return {
      json: {
        ...data,
        fileUrl: data.LinkingUrl
      }
    };
  }

  // Construct versioned URL
  let fileUrl = '';

  if (data.ServerRelativeUrl && data.ContentTag) {
    // Base URL with server relative path
    fileUrl = 'https://nosta.sharepoint.com' + data.ServerRelativeUrl;

    // Extract GUID from ContentTag and create version parameter
    const guidMatch = data.ContentTag.match(/\{([^}]+)\}/);
    if (guidMatch) {
      const versionId = guidMatch[1].toLowerCase().replace(/-/g, '');
      fileUrl += `?d=w${versionId}`;
    }
  }

  return {
    json: {
      ...data,
      fileUrl: fileUrl
    }
  };
});

return outputItems;

const DEFAULT_CHUNK_SIZE = 2000;   // chunk size
const DEFAULT_OVERLAP = 0.3;       // 30% overlap

function splitTextWithOverlap(text, chunkSize, overlap) {
  const step = Math.max(1, Math.floor(chunkSize * (1 - overlap)));
  const parts = [];
  for (let start = 0; start < text.length; start += step) {
    parts.push(text.slice(start, start + chunkSize));
  }
  return parts;
}

function extractUrl(text) {
  if (!text) return "";
  const match = text.match(/https?:\/\/[^\s)'"<>]+/);
  return match ? match[0] : "";
}

const incoming = $input.item.json;

// 1. Combine fields for embedding
const combinedText = [
  incoming.summary || "",
  incoming["cleaned markdown"] || "",
  incoming["process markdown"] || ""
].join("\n\n");

// 2. Pick only ONE URL
let url = incoming.url || "";
if (!url) {
  url = extractUrl(incoming["cleaned markdown"]) || extractUrl(incoming["raw markdwon"]);
}

// 3. Chunk
const parts = splitTextWithOverlap(combinedText, DEFAULT_CHUNK_SIZE, DEFAULT_OVERLAP);

// 4. Build output with metadata
let charPos = 0;
const response = parts.map((part, idx) => {
  const from = charPos;
  const to = charPos + part.length;
  const out = {
    content: part,
    metadata: {
      title: incoming.title || "",
      url,                 // ✅ only one URL
      page: 1,
      chunk_index: idx,
      loc: { Characters: { from, to } }
    }
  };
  charPos = to;
  return { json: out };
});

return response;
